import React, { useState } from "react";
import styles from "./RegisterError.module.css";

interface RegisterErrorProps {
  onSwitchToLogin: () => void;
  onClose: () => void;
}

const RegisterError: React.FC<RegisterErrorProps> = ({
  onSwitchToLogin,
  onClose,
}) => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");

  const handleRegister = () => {
    // Здесь будет логика регистрации
    onClose();
  };

  return (
    <div className={styles.registerErrorContainer}>
      <img
        src={`${process.env.PUBLIC_URL}/images/logo.svg`}
        alt="SkyFitnessPro"
        className={styles.logo}
      />

      <div className={styles.formContainer}>
        <input
          type="email"
          placeholder="Эл.почта"
          className={styles.inputField}
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Пароль"
          className={styles.inputField}
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <input
          type="password"
          placeholder="Повторить пароль"
          className={styles.inputField}
          value={confirmPassword}
          onChange={(e) => setConfirmPassword(e.target.value)}
        />

        <div className={styles.errorMessage}>
          Данная почта уже используется.
          <br />
          Попробуйте войти.
        </div>

        <button className={styles.registerButton} onClick={handleRegister}>
          Зарегистрироваться
        </button>

        <button className={styles.loginButton} onClick={onSwitchToLogin}>
          Войти
        </button>
      </div>
    </div>
  );
};

export default RegisterError;
